function classes(node) {
  return String(node.className || '').split(/\s+/).filter(Boolean);
}

function hasClass(node, cls) {
  return classes(node).includes(cls);
}

function parseStep(step) {
  // supports: tag, .cls, #id, tag.cls
  const s = step.trim();
  if (!s) return null;

  if (s.startsWith('#')) return { kind: 'id', id: s.slice(1) };
  if (s.startsWith('.')) return { kind: 'class', cls: s.slice(1) };

  const [tag, cls] = s.split('.');
  if (cls) return { kind: 'tagClass', tag, cls };
  return { kind: 'tag', tag: s };
}

function matchesStep(node, stepObj) {
  if (!node || node.nodeType !== 1) return false;

  switch (stepObj.kind) {
    case 'id':
      return String(node.id || '') === stepObj.id;
    case 'class':
      return hasClass(node, stepObj.cls);
    case 'tag':
      return String(node.tagName || '').toLowerCase() === String(stepObj.tag).toLowerCase();
    case 'tagClass':
      return (
        String(node.tagName || '').toLowerCase() === String(stepObj.tag).toLowerCase() &&
        hasClass(node, stepObj.cls)
      );
    default:
      return false;
  }
}

function parseSelector(selector) {
  // collapse whitespace, split by spaces (descendant combinator)
  const parts = String(selector).trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return [];

  const steps = [];
  for (const p of parts) {
    const step = parseStep(p);
    if (!step) return [];
    steps.push(step);
  }
  return steps;
}

function matchesChain(el, steps) {
  // steps are descendant chain, e.g. [#main, button.primary]
  // match from last step, then find ancestors for previous steps
  let cur = el;
  if (!matchesStep(cur, steps[steps.length - 1])) return false;

  for (let i = steps.length - 2; i >= 0; i--) {
    const needed = steps[i];
    let anc = cur.parentNode || null;
    let found = null;
    while (anc) {
      if (matchesStep(anc, needed)) {
        found = anc;
        break;
      }
      anc = anc.parentNode || null;
    }
    if (!found) return false;
    cur = found;
  }
  return true;
}

function dfs(root, visit) {
  const children = Array.isArray(root.childNodes) ? root.childNodes : [];
  for (const child of children) {
    if (child && child.nodeType === 1) visit(child);
    dfs(child || {}, visit);
  }
}

export default function queryAll(root, selector) {
  if (!root || root.nodeType !== 1) {
    throw new TypeError('queryAll: root must be an element node');
  }
  if (typeof selector !== 'string' || selector.trim() === '') {
    throw new TypeError('queryAll: selector must be a non-empty string');
  }

  const steps = parseSelector(selector);
  if (steps.length === 0) return [];

  const out = [];

  // consider root itself as candidate too
  if (matchesChain(root, steps)) out.push(root);

  dfs(root, (el) => {
    if (matchesChain(el, steps)) out.push(el);
  });

  return out;
}
